import React, { useEffect, useState } from 'react'
import { Row, Card, Switch, Col, Input, Select, Spin, Button, Space } from 'antd';
import { containerConstantsService } from '../../utils/containerconstants/ContainerConstants';
import BreadCrumb from '../commoncomponent/breadcrumb/bread_crumb';
import { getUserType } from '../APIConfig/MasterDataAction';
import { fetchBulkUploadAddShipmentConfig, saveBulkUploadAddShipmentConfig } from '../APIConfig/BulkUploadAddShipmentAction';
import { useStore } from '../hook-store/store';
import {getBasePath} from '../commoncomponent/BasePath';
import { notifyResponseMessage } from '../commoncomponent/NotificationComponent/notifyResponseMessage';
import { STATUS } from '../../utils/constants';
import '../../CSS/BulkUploadAddShipment.css';

const containerConstants = containerConstantsService.getInstance();
const BulkUploadAddShipment = (props) => {
    const store = useStore(true)[0];
    const [showLoading, setShowLoading] = useState(false);
    const [title, setTitle] = useState("Bulk Upload");
    const [selectedUserTypes, setSelectedUserTypes] = useState([]);    
    const [allUserTypeListOption, setAllUserTypeListOption] = useState([]);
    const [bulkUploadEnabled, setBulkUploadEnabled] = useState(false);
    const [bulkUploadConfigId, setBulkUploadConfigId] = useState(0);
    const [isButtonDisabled, setIsButtonDisabled] = useState(true);
    const [dataFetched, setDataFetched] = useState(false);
    const [ basePath, setBasePath ]  = useState(''); 

    const urlList =
        [
            {
                url: basePath +'/v2/label_generation/v2/settings',
                heading: containerConstants.formatString(containerConstants.SETTINGS),
            },
            {
                url: basePath +'/v2/label_generation/settings',
                heading: containerConstants.formatString(containerConstants.ADD_ORDER_AND_GENERATE_LABEL)
            },
            {
                url: basePath +'/v2/label_generation/settings',
                heading: containerConstants.formatString(containerConstants.BULK_UPLOAD)
            }            
        ];
    const urlListForNewSetting =
        [
            {
                url: '/v2/new_settings/label_generation/settings',
                heading: containerConstants.formatString(containerConstants.ADD_ORDER_AND_GENERATE_LABEL)
            },
            {
                url: '/v2/new_settings/label_generation/bulk_upload',
                heading: containerConstants.formatString(containerConstants.CARRIER_ALLOCATION_AND_MASTER_VALIDATION)
            }
        ];


    const switchClickHandler = (checked) => {
        if( ! checked ){
            setSelectedUserTypes([]);
            setTitle("Bulk Upload");
            setIsButtonDisabled(false);    
        }
        setBulkUploadEnabled(checked);        
    };

    const handleTitleInputChange = (value)=> {
        setTitle(value);
        isSaveButtonDisable('title', value)        
    }

    const saveConfig = () => {
        setShowLoading(true);
        let lgBulkUploadSettingDto = {
            "isEnabled":bulkUploadEnabled,
            "title":title,
            "allowedUserTypes":selectedUserTypes,
            "id":bulkUploadConfigId,
        }
        saveBulkUploadAddShipmentConfig(lgBulkUploadSettingDto)
                .then(response => {
                    setShowLoading(false);
                    if (response && response.status === 200) {
                        let status = response?.data?.status;
                        if (status && status.toUpperCase() === STATUS.SUCCESS) {
                            setBulkUploadConfigId(response.data.data.id)                            
                            notifyResponseMessage(STATUS.SUCCESS, response?.data?.message);
                            props.updateLabelGenerationTitle(response.data.data);
                        } else {
                            notifyResponseMessage(STATUS.FAILED, response?.data?.message);
                        }
                    }
                })
                .catch(error => {
                    setShowLoading(false);

                    notifyResponseMessage(STATUS.ERROR, error);
                });
    }

    const isSaveButtonDisable = (key, value) => {
        if( key ){
            switch( key ){
                case 'title':
                    if( value && selectedUserTypes.length > 0 ){
                        setIsButtonDisabled(false);
                    } else{
                        setIsButtonDisabled(true);
                    }
                    break;
                case 'selectedUserTypes': 
                    if( title && value.length > 0 ){
                        setIsButtonDisabled(false);
                    } else{
                        setIsButtonDisabled(true);
                    }
                    break;
                default:
                    break;
            }
        }else{
            if(title && selectedUserTypes.length > 0 ){
                setIsButtonDisabled(false);
            } else{
                setIsButtonDisabled(true);
            }
        }
    }   

    useEffect(() => {
        setBasePath(getBasePath(props, store));
        document.title = containerConstants.formatString(containerConstants.BULK_UPLOAD);
        let options = []
        allUserTypeListOption.length === 0 && getUserType()
        .then(response => {
            if (response.status === 200) {
                response.data.map(userType => {
                    options.push({
                        label: userType.name,
                        value: userType.id,                        
                      })
                })
            }                    
            setAllUserTypeListOption(options);
        })
        .catch(error => {

        });

        ! dataFetched && fetchBulkUploadAddShipmentConfig(bulkUploadConfigId)
        .then(response => {
            if (response && response.status === 200) {
                let status = response?.data?.status;
                if (status && (status.toUpperCase() === STATUS.SUCCESS)) {
                    setDataFetched(true);
                    if(response.data && response.data.data ){
                        let reps = response.data.data ;                        
                        let userTypes = []  ;
                        reps.allowedUserTypes && reps.allowedUserTypes.forEach(val=>{
                            val && userTypes.push(parseInt(val));
                        });
                        setSelectedUserTypes(userTypes);
                        setTitle(reps.title);
                        setBulkUploadEnabled(reps.isEnabled);
                        setBulkUploadConfigId(reps.id);
                        isSaveButtonDisable();
                    }
                }
            }
        });
    },[allUserTypeListOption, dataFetched]);

    return (
        <div>
        <BreadCrumb urlList={store.fromNewSetting ? urlListForNewSetting :urlList} />
        <Spin spinning={showLoading}>
            <Card className='fw400 fs12 lh18' size='small' bodyStyle={{ color: '#727272' }} id='bulk-upload-add-shipment-card'>
                
                <Row>
                    <Col span={7}>
                        <h3 style={{fontFamily: 'Roboto', fontStyle: 'normal', fontWeight: 'normal', fontsize: '14px', lineHeight: '22px', color: '#212121'}}>
                        {containerConstants.formatString(containerConstants.ENABLED)} :
                        </h3>
                    </Col>
                    <Col span={10}>
                        <Switch checked = {bulkUploadEnabled} onChange={switchClickHandler} />                        
                    </Col>
                </Row>

                { bulkUploadEnabled && <Row style={{ marginTop: '12px' }}>
                        <Col span={7}>
                        <h3 style={{fontFamily: 'Roboto', fontStyle: 'normal', fontWeight: 'normal', fontsize: '14px', lineHeight: '22px', color: '#212121'}}>                     
                            {containerConstants.formatString(containerConstants.TITLE)} :
                        </h3>
                        </Col>
                        <Col span={12}>
                            <div style={{ width: '100%' }} >
                                <Input
                                    style={{  height: '32px' }}
                                    placeholder="Add title"
                                    name="title"
                                    value={title}
                                    onChange={(e) => handleTitleInputChange(e.target.value)}/>
                            </div>
                        </Col>
                    </Row>
                }
                { bulkUploadEnabled &&
                    <Row style={{ marginTop: '12px' }}>
                        <Col span={7}>
                            <h3 style={{fontFamily: 'Roboto', fontStyle: 'normal', fontWeight: 'normal', fontsize: '14px', lineHeight: '22px', color: '#212121'}}>
                                {containerConstants.formatString(containerConstants.USER_TYPE)} :
                            </h3>
                        </Col>
                        <Col span={12}>
                            <div style={{ width: '100%' }}>
                                <Select
                                    placeholder='Select User Types'                                    
                                    mode='multiple'
                                    showSearch
                                    style={{display: 'block'}}
                                    value={selectedUserTypes}
                                    onChange={value => {
                                            setSelectedUserTypes(value)
                                            isSaveButtonDisable('selectedUserTypes', value)
                                        }
                                    }
                                    filterOption={(input, option) => {
                                        if(option.props?.children)
                                        return option.props.children.toLowerCase().indexOf(input.toLowerCase()) >= 0
                                    }}
                                    options={ allUserTypeListOption }
                                >                                   
                                </Select>
                            </div>
                        </Col>
                    </Row> 
                }
                <Row style={{ marginTop: '24px' }}>
                    <Col push={15} >
                        <div disabled = { store.fromFCR ? false : store.showCustom }>
                            <Space size={9}>
                                <Button
                                    ghost
                                    className='fw500 fs14 lh22'
                                    style={{ color: '#727272', border: 0 }}
                                    type="primary"
                                    loading = {showLoading}
                                >
                                    {containerConstants.formatString(containerConstants.CANCEL)}
                                </Button>
                                <Button
                                    className='fw500 fs14 lh22'
                                    style={{ color: '#FFFFFF' }}
                                    type="primary"
                                    loading = {showLoading}
                                    onClick={saveConfig}
                                    disabled = {isButtonDisabled }
                                >
                                    {containerConstants.formatString(containerConstants.SAVE)}
                                </Button>
                            </Space>
                        </div>
                    </Col>
                </Row>
            </Card>
            </Spin>
        
        </div>
    )
}

export default BulkUploadAddShipment
